-- Batch 12: cardiovascular and vascular catalog.
select public.seed_structured_concept(
  'expansion-batch-12', slug, 'Cardiovascular', condition, cue, action, teaching,
  danger,
  'Delay assessment until the next routine visit',
  'Encourage strenuous activity during clinical instability',
  'Stop prescribed treatment without clinician review',
  client_need
)
from (values
('vasospastic-angina','vasospastic angina','rest pain with transient ST elevation that resolves','Assess active pain and give prescribed vasodilator therapy while excluding acute infarction','Avoid tobacco and triggers and use calcium-channel blocker or nitrate therapy as prescribed','Pain persists with hemodynamic instability','Physiological Adaptation'),
('nstemi','non-ST-elevation acute coronary syndrome','ischemic pain with ST depression or T-wave change and rising troponin','Activate acute coronary care and provide prescribed antiplatelet, anticoagulant, anti-ischemic, and invasive evaluation','Call emergency services for persistent pressure, dyspnea, diaphoresis, or nausea','Recurrent pain with ventricular dysrhythmia and shock','Physiological Adaptation'),
('acute-pericarditis','acute pericarditis','sharp positional chest pain, friction rub, and diffuse ST elevation','Assess for effusion and tamponade and provide prescribed anti-inflammatory treatment','Sit forward for comfort and report faintness, breathlessness, or increasing pressure','Hypotension, jugular venous distention, and muffled heart sounds','Physiological Adaptation'),
('infective-endocarditis','infective endocarditis','fever, new murmur, embolic findings, and positive blood cultures','Obtain ordered cultures promptly and begin targeted prolonged antimicrobial therapy','Complete antibiotics and report stroke signs, heart failure, recurrent fever, or line problems','Acute focal deficit with pulmonary edema and hypotension','Physiological Adaptation'),
('acute-myocarditis','acute myocarditis','viral prodrome followed by chest pain, dysrhythmia, and heart failure','Limit cardiac workload, monitor rhythm and function, and treat heart failure and cause as prescribed','Avoid strenuous exercise until cleared and report syncope, palpitations, or worsening dyspnea','Ventricular tachycardia with cardiogenic shock','Physiological Adaptation'),
('rheumatic-heart','rheumatic heart disease','history of rheumatic fever with progressive valvular murmur and dyspnea','Assess valve function and heart failure and ensure indicated infection prevention and follow-up','Treat streptococcal infection promptly and maintain prescribed secondary prophylaxis','Acute pulmonary edema with new atrial fibrillation','Physiological Adaptation'),
('aortic-stenosis','severe aortic stenosis','exertional syncope, angina, dyspnea, and harsh systolic murmur','Maintain perfusion, avoid abrupt preload reduction, and prepare definitive valve evaluation','Report exertional faintness, chest pain, or breathlessness and avoid unapproved intense exertion','Syncope with hypotension and pulmonary edema','Physiological Adaptation'),
('mitral-stenosis','mitral stenosis','dyspnea, atrial fibrillation, hemoptysis, and diastolic murmur','Control rate and congestion, assess embolic risk, and prepare valve intervention when indicated','Report palpitations, stroke signs, increasing dyspnea, or coughing blood','Rapid atrial fibrillation with pulmonary edema','Physiological Adaptation'),
('mitral-regurgitation','acute severe mitral regurgitation','sudden dyspnea, new systolic murmur, and pulmonary edema','Support oxygenation and circulation and obtain urgent valve and surgical evaluation','Report increasing breathlessness, palpitations, edema, or reduced activity tolerance','Cardiogenic shock with severe pulmonary edema','Physiological Adaptation'),
('hypertrophic-cardiomyopathy','hypertrophic cardiomyopathy','exertional syncope, family history of sudden death, and dynamic murmur','Maintain preload, control rate as prescribed, and assess sudden-death risk','Avoid dehydration and unapproved intense exercise and report syncope or family sudden death','Exertional collapse with ventricular tachycardia','Physiological Adaptation'),
('dilated-cardiomyopathy','dilated cardiomyopathy','reduced ejection fraction, displaced impulse, congestion, and dysrhythmia','Treat heart failure, monitor rhythm and thromboembolism risk, and evaluate reversible causes','Track weight and symptoms and avoid alcohol or cardiotoxic exposure','New embolic stroke with decompensated heart failure','Physiological Adaptation'),
('right-heart-failure','right-sided heart failure','jugular venous distention, hepatomegaly, ascites, and peripheral edema','Assess volume and organ perfusion and give prescribed diuretic and cause-directed therapy','Track daily weight and report rapid gain, swelling, abdominal fullness, or reduced urine','Hypotension with worsening renal and hepatic perfusion','Physiological Adaptation'),
('cor-pulmonale','cor pulmonale','chronic lung disease with right-heart strain, edema, and hypoxemia','Optimize oxygenation and lung treatment while managing right-heart congestion','Use oxygen and pulmonary medicines as prescribed and report increasing edema or syncope','Severe hypoxemia with right-heart shock','Physiological Adaptation'),
('peripheral-artery-disease','peripheral arterial disease','claudication, cool hairless legs, weak pulses, and delayed healing','Assess limb perfusion and promote antiplatelet, risk reduction, and supervised walking therapy','Stop tobacco, protect feet, and report rest pain, color change, or nonhealing wounds','Sudden cold pulseless painful limb','Reduction of Risk Potential'),
('acute-limb-ischemia','acute limb ischemia','sudden pain, pallor, pulselessness, paresthesia, and weakness','Notify vascular surgery emergently, protect the limb, and begin prescribed anticoagulation','Seek emergency care for sudden limb pain, coldness, numbness, or weakness','Progressing paralysis and sensory loss','Physiological Adaptation'),
('chronic-venous-insufficiency','chronic venous insufficiency','dependent edema, brown skin change, and irregular ankle ulcer','Promote compression when arterial flow is adequate, elevation, walking, and wound care','Protect skin, use prescribed compression, and report infection or sudden unilateral swelling','Spreading cellulitis with fever or suspected deep-vein thrombosis','Basic Care and Comfort'),
('buerger-disease','thromboangiitis obliterans','young tobacco user with distal ischemia, ulcers, and absent pulses','Support complete tobacco and nicotine cessation and protect ischemic extremities','Any tobacco or nicotine exposure can continue vascular injury','New gangrene with rest pain and infection','Physiological Adaptation'),
('raynaud-phenomenon','Raynaud phenomenon','episodic white-blue-red digits triggered by cold or stress','Warm gradually, remove triggers, and assess for tissue injury and secondary disease','Keep the body and hands warm and avoid tobacco and vasoconstrictors','Persistent ischemia with ulceration or necrosis','Basic Care and Comfort'),
('aaa-screening','abdominal aortic aneurysm screening','an older adult with smoking history asks about prevention','Assess eligibility for one-time ultrasound screening and aggressively manage vascular risk','Screening applies to selected risk groups and new pulsatile pain requires emergency care','Sudden abdominal or back pain with hypotension','Health Promotion and Maintenance'),
('vascular-graft-occlusion','vascular graft occlusion','a postoperative limb becomes cool with disappearing distal pulses','Notify the vascular team immediately and assess the full neurovascular status','Report sudden pain, numbness, coolness, color change, or pulse loss','Progressive motor and sensory loss below the graft','Reduction of Risk Potential'),
('synchronized-cardioversion','synchronized cardioversion','an unstable tachyarrhythmia with a pulse','Activate synchronization, provide sedation when feasible, clear the client, and deliver prescribed energy','Continue anticoagulation and rhythm medicines as directed and report recurrence','Shock is delivered unsynchronized on the T wave','Reduction of Risk Potential'),
('defibrillation-safety','defibrillation','ventricular fibrillation without a pulse','Begin CPR, charge the defibrillator, clear all contact, shock, and resume CPR immediately','Early CPR and defibrillation are critical; follow emergency-response instructions','A responder remains in contact with the bed during shock','Safety and Infection Prevention and Control'),
('frequent-pvcs','frequent premature ventricular complexes','multifocal ectopy with chest pain and low potassium','Assess perfusion and ischemia, correct causes, and monitor for sustained ventricular rhythm','Report syncope, chest pain, or sustained palpitations and follow electrolyte instructions','PVCs progress to sustained ventricular tachycardia with hypotension','Physiological Adaptation'),
('stable-vtach','stable monomorphic ventricular tachycardia','wide regular tachycardia with a pulse and preserved pressure','Assess stability continuously and give prescribed antiarrhythmic or synchronized treatment','Report recurrent palpitations, syncope, chest pain, or device shocks','The client becomes hypotensive and unresponsive','Physiological Adaptation'),
('torsades','torsades de pointes','polymorphic ventricular tachycardia with prolonged QT','Stop QT-prolonging causes, give prescribed magnesium, and defibrillate if pulseless','Check before adding interacting medicines and report syncope or seizure','The rhythm becomes pulseless','Physiological Adaptation'),
('ventricular-fibrillation','ventricular fibrillation','chaotic rhythm with no pulse or effective circulation','Start high-quality CPR and defibrillate as soon as possible','Use emergency response and an AED immediately for unresponsiveness without normal breathing','Defibrillation is delayed despite an available device','Physiological Adaptation'),
('asystole','asystolic cardiac arrest','an unresponsive pulseless client with a flat rhythm in two leads','Begin CPR, give prescribed epinephrine, confirm rhythm, and treat reversible causes','Asystole is not a shockable rhythm; continuous CPR and cause correction are essential','CPR is interrupted for prolonged repeated pulse checks','Physiological Adaptation'),
('pea','pulseless electrical activity','organized electrical activity without a palpable pulse','Begin CPR, give prescribed epinephrine, and rapidly identify reversible causes','Electrical activity does not guarantee circulation; pulse assessment guides action','Treatment is delayed while rhythm is mistaken for perfusion','Physiological Adaptation'),
('first-degree-block','first-degree AV block','prolonged PR interval with every P wave conducted','Assess symptoms and causes and monitor when clinically indicated','Often no treatment is needed, but report faintness, chest pain, or medicine-related slowing','The block progresses with hypotension and syncope','Reduction of Risk Potential'),
('mobitz-one','second-degree AV block Mobitz I','progressive PR lengthening followed by a dropped beat','Assess perfusion and causes and monitor for symptomatic bradycardia','Report dizziness or fainting and review AV-node-slowing medicines','Hypotension develops with worsening block','Reduction of Risk Potential'),
('mobitz-two','second-degree AV block Mobitz II','constant PR intervals with unexpected dropped QRS complexes','Prepare pacing and urgent evaluation even before complete block develops','Report syncope or severe dizziness and keep pacing follow-up','The rhythm progresses to complete heart block','Physiological Adaptation'),
('complete-heart-block','complete heart block','independent atrial and ventricular rhythms with severe bradycardia','Support perfusion and initiate emergency pacing','Keep pacemaker care and report syncope, chest pain, or severe weakness','Cardiogenic shock with ventricular standstill','Physiological Adaptation'),
('icd-shock','implantable cardioverter-defibrillator discharge','a client reports a device shock','Assess symptoms and rhythm and follow the device-specific emergency plan','Report repeated shocks, syncope, chest pain, or persistent symptoms immediately','Multiple shocks occur with ongoing ventricular tachycardia','Reduction of Risk Potential'),
('pacemaker-home','permanent pacemaker self-care','a client is preparing for discharge after implantation','Verify function and teach incision, movement, identification, monitoring, and device precautions','Carry device identification and report syncope, persistent hiccups, infection, or slow pulse','Redness and drainage occur with failure to capture','Health Promotion and Maintenance'),
('cardiac-rehabilitation','cardiac rehabilitation','a stable client is recovering after myocardial infarction','Use supervised progressive exercise, risk reduction, medication adherence, nutrition, and psychosocial support','Warm up, follow target intensity, and stop for chest pain, faintness, or unusual breathlessness','Exertional chest pain persists after stopping activity','Health Promotion and Maintenance'),
('endocarditis-prevention','infective endocarditis prevention','a high-risk valve client asks about dental care','Clarify whether prophylaxis is indicated and promote excellent oral health','Tell dental clinicians about the heart condition and use antibiotics only when prescribed','Fever and a new murmur develop after an invasive infection','Health Promotion and Maintenance'),
('lipid-management','atherosclerotic risk reduction','a client has markedly elevated LDL and vascular disease','Combine indicated statin therapy with adherence, nutrition, activity, and secondary-cause review','Take medicine consistently and report severe muscle symptoms or dark urine','Acute coronary symptoms occur while therapy is stopped independently','Health Promotion and Maintenance'),
('resistant-hypertension','resistant hypertension','blood pressure remains high on several medicines','Confirm measurement and adherence and evaluate substances and secondary causes','Use home readings and avoid unapproved decongestants, NSAIDs, and excess sodium','Severe pressure occurs with neurologic deficits or pulmonary edema','Reduction of Risk Potential'),
('orthostatic-hypotension','orthostatic hypotension','dizziness and pressure drop after standing','Review causes and medicines and use slow position change, hydration, and compression when appropriate','Sit before standing, pause at bedside, and ask for help when dizzy','Syncope causes head injury or occurs with gastrointestinal bleeding','Basic Care and Comfort'),
('pericardiocentesis-care','pericardiocentesis','a client undergoes drainage for tamponade','Monitor rhythm, pressure, oxygenation, drainage, puncture site, and recurrence','Report chest pressure, faintness, dyspnea, or palpitations after the procedure','Hypotension returns with jugular venous distention','Reduction of Risk Potential'),
('arterial-line','arterial-line monitoring','continuous invasive pressure monitoring is used','Level and zero the system, assess waveform and limb perfusion, and maintain the pressure bag','Protect the catheter and report bleeding, numbness, coolness, or severe pain','The distal limb becomes cold and pulseless','Reduction of Risk Potential'),
('central-venous-pressure','central venous pressure monitoring','a central line is used to trend right-sided filling pressure','Level and zero correctly and interpret trends with the full clinical assessment','Position changes affect readings and one number never replaces assessment','The line disconnects causing bleeding or air entry','Reduction of Risk Potential'),
('pulmonary-artery-catheter','pulmonary artery catheter monitoring','a critically ill client has invasive hemodynamic monitoring','Verify waveform and position and use the minimum wedge time while monitoring rhythm','Report chest pain, dyspnea, or catheter alarms and avoid manipulating the line','A balloon remains inflated or ventricular tachycardia occurs','Reduction of Risk Potential'),
('iabp','intra-aortic balloon pump support','a client has cardiogenic shock with femoral IABP access','Maintain timing and limb alignment and monitor perfusion, bleeding, urine, and device alarms','Keep the affected leg straight and report back pain, numbness, coolness, or alarms','Loss of distal pulses with sudden back pain and hypotension','Physiological Adaptation'),
('ecmo-circuit','ECMO support','a client receives extracorporeal cardiopulmonary support','Monitor circuit integrity, anticoagulation, oxygenation, perfusion, bleeding, and limb status continuously','Family should avoid touching equipment and immediately report alarms or visible bleeding','Circuit failure, major bleeding, or abrupt oxygenation loss occurs','Physiological Adaptation'),
('heart-transplant-rejection','heart transplant rejection','a transplant recipient develops fatigue, dyspnea, dysrhythmia, and reduced function','Notify the transplant team and evaluate urgently for rejection and infection','Take immunosuppression exactly and report fever, weight gain, fatigue, palpitations, or dyspnea','Hemodynamic compromise develops with ventricular dysfunction','Physiological Adaptation'),
('heart-transplant-denervation','the denervated transplanted heart','a stable recipient asks about exercise and chest pain','Use transplant-specific monitoring because resting rate and symptom responses differ','Warm up and cool down longer and report reduced exercise tolerance or atypical ischemic symptoms','Silent ischemia progresses with unexplained dyspnea and dysfunction','Health Promotion and Maintenance'),
('cardiac-cachexia','cardiac cachexia','advanced heart failure with unintentional weight and muscle loss','Assess congestion, intake, inflammation, function, and goals with multidisciplinary nutrition support','Use small nutrient-dense meals and report rapid weight change or worsening swelling','Severe wasting accompanies hypotension and inability to eat','Basic Care and Comfort')
) as c(slug,condition,cue,action,teaching,danger,client_need);

